#include <stdio.h>

int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &N);
        const char *deck = (N <= 15) ? "Lower" : "Upper";
        int pos = (N <= 15) ? N : N - 15;
        const char *type = (pos <= 10) ? "Double" : "Single";
        printf("%s %s\n", deck, type);
    }
    return 0;
}

